import{_ as e}from"./chunks/export.CcCpNx0w.js";import{_ as t,o as a,c as r,ae as d}from"./chunks/framework.C00B0EYs.js";const g=JSON.parse('{"title":"导出流程","description":"从 Motor Sound Editor 准备并导出项目打包产物。","frontmatter":{"title":"导出流程","description":"从 Motor Sound Editor 准备并导出项目打包产物。"},"headers":[],"relativePath":"zh/docs/guide/export.md","filePath":"zh/docs/guide/export.md"}'),i={name:"zh/docs/guide/export.md"};function n(s,o,l,c,p,h){return a(),r("div",null,[...o[0]||(o[0]=[d('<h1 id="导出流程" tabindex="-1">导出流程 <a class="header-anchor" href="#导出流程" aria-label="Permalink to &quot;导出流程&quot;">​</a></h1><p>当你完成音轨编辑和曲线调整后，就可以将当前工程导出为目标模拟器可用的打包产物。</p><h2 id="_1-导出前检查项" tabindex="-1">1. 导出前检查项 <a class="header-anchor" href="#_1-导出前检查项" aria-label="Permalink to &quot;1. 导出前检查项&quot;">​</a></h2><p>在进行导出之前，请确认：</p><ul><li><strong>有效音轨</strong>：导出引擎只会处理 <strong>已启用（Enabled）</strong>、<strong>未静音（Unmuted）</strong> 且 <strong>已分配音频资源</strong> 的轨道。</li><li><strong>至少存在一条可导出轨道</strong>：如果所有可导出轨道都没有分配音频资源，导出会直接报错。</li></ul><h2 id="_2-导出对话框" tabindex="-1">2. 导出对话框 <a class="header-anchor" href="#_2-导出对话框" aria-label="Permalink to &quot;2. 导出对话框&quot;">​</a></h2><p><img src="'+e+'" alt="项目导出"></p><p>点击导出按钮后，会弹出 <strong>Export File</strong> 对话框，你可以在这里配置最终输出的格式和音频参数。</p><h2 id="_3-导出格式" tabindex="-1">3. 导出格式 <a class="header-anchor" href="#_3-导出格式" aria-label="Permalink to &quot;3. 导出格式&quot;">​</a></h2><ul><li><strong>BVE</strong>：当前唯一可用的导出格式。选择后，软件会自动生成标准的 <strong>ZIP 压缩包</strong>，例如 <code>[项目名称]-BVE.zip</code>。</li><li><strong>OpenBVE / MTR</strong>：目前仍是禁用状态，仅作为未来扩展目标的占位项显示在界面中。</li></ul><h2 id="_4-采样率" tabindex="-1">4. 采样率 <a class="header-anchor" href="#_4-采样率" aria-label="Permalink to &quot;4. 采样率&quot;">​</a></h2><p>你可以为导出的音频指定全局采样率。</p><ul><li>可选值包括：<code>22050 Hz</code>、<code>32000 Hz</code>、<code>44100 Hz</code>、<code>48000 Hz</code>、<code>96000 Hz</code>。</li><li>默认推荐值通常是 <code>44100 Hz</code>，能在音质与文件体积之间取得较好的平衡。</li></ul><h2 id="_5-格式转换与自动适配" tabindex="-1">5. 格式转换与自动适配 <a class="header-anchor" href="#_5-格式转换与自动适配" aria-label="Permalink to &quot;5. 格式转换与自动适配&quot;">​</a></h2><p>Motor Sound Editor 原生支持导入 <code>.ogg</code> 和 <code>.wav</code> 音频。为了保证导出结果符合目标格式要求，软件会在导出时自动执行必要的转换。</p><p>如果项目中存在 <code>.ogg</code> 音频，而导出目标需要 WAV，导出对话框底部会显示提示信息，说明这些 OGG 文件会在导出时自动转换成 WAV。</p><p>你无需手动转码。确认配置无误后，点击 <strong>Export</strong> 即可完成导出。</p>',17)])])}const m=t(i,[["render",n]]);export{g as __pageData,m as default};
